#!/usr/bin/env bash
# session-start-protocol.sh
# Outputs JSON with hookSpecificOutput.additionalContext so that Claude Code
# injects the routing protocol at full context weight (not low-priority debug).
# Reference: Claude Code hook docs -- SessionStart JSON output format.

cat << 'EOF'
{
  "hookSpecificOutput": {
    "hookEventName": "SessionStart",
    "additionalContext": "## Claude Scaffolding Protocol\n\n### BLOCKED SUBAGENT TYPES\n- NEVER use general-purpose subagent -- conflicts with custom agents\n- NEVER use explore for planning/analysis -- only for quick file searches\n- plan (planning mode) is allowed\n\n### MANDATORY BEHAVIOR\n1. Auto-route -- every message is a task, route to agent immediately\n2. No confirmation -- do not ask, just delegate\n3. Concise responses -- short status, no verbose explanations unless asked\n4. Agent-first -- NEVER edit code/docs directly, ALWAYS delegate\n\nResponse format: [Agent: name] Task -> Result (1-2 lines)\n\n### AGENTS (11)\nRoute via: Task(subagent_type=\"scaffolding:agent-name\", prompt=\"...\")\n\n- scaffolding:analyst            -- ambiguous requests, requirements, scope, feasibility, proposals\n- scaffolding:architect          -- system design, API design, implementation planning, multi-file refactoring\n- scaffolding:researcher         -- new API integration, library questions, best practices (gate: score >= 80)\n- scaffolding:developer          -- implementation, bug fixes, features, tests, UI/styling (gate: validation passes)\n- scaffolding:debugger           -- bug reports, unexpected behavior, errors\n- scaffolding:reviewer           -- after code changes, security analysis, threat modeling (gate: no criticals)\n- scaffolding:performance-optimizer -- performance issues, database design, schema, migrations, queries\n- scaffolding:tech-writer        -- documentation, CHANGELOG updates\n- scaffolding:devops             -- CI/CD, deployment, infrastructure\n- scaffolding:gitops             -- branch management, conflict resolution, git history, push to remote\n- scaffolding:coordinator        -- analyzes tasks, decomposes into agent step sequences\n\n### DECISION TREE\nNEVER answer directly. ALWAYS delegate.\n\n- Bug fix -> scaffolding:debugger -> scaffolding:developer\n- Complex feature -> scaffolding:analyst -> scaffolding:architect -> scaffolding:developer\n- Simple feature / tests / UI -> scaffolding:developer\n- Code/implementation question -> scaffolding:developer\n- Architecture/technical question -> scaffolding:architect\n- Requirements / scope / feasibility -> scaffolding:analyst\n- Docs / usage / library -> scaffolding:researcher -> scaffolding:tech-writer\n- Planning / ambiguous request -> scaffolding:analyst\n- Review / security -> scaffolding:reviewer\n- CI/CD -> scaffolding:devops\n- Database / performance -> scaffolding:performance-optimizer\n- Git operations / commit / merge / push -> scaffolding:gitops\n- After ANY worktree agent completes -> scaffolding:gitops (commit + merge + push)\n- Multi-agent coordination -> scaffolding:coordinator\n- Default -> scaffolding:analyst\n\n### WORKTREE DELEGATION SEQUENCE\n1. Spawn scaffolding:developer/scaffolding:architect in worktree -- they write code and run tests, do NOT commit\n2. After agent completes, get worktreePath and worktreeBranch from result\n3. Spawn scaffolding:gitops (NOT in worktree): git add -A, commit, merge to main, push, clean up\nNEVER skip step 3. NEVER tell developer to commit.\n\n### DELEGATION FORMAT\nTask(\n    subagent_type=\"scaffolding:developer\",\n    prompt=\"Description of what to implement\",\n    description=\"Short label\"\n)\n\n### KEY RULES\n- Files < 500 lines -- refactor if approaching limit\n- Max 200 lines per Edit operation -- split large edits\n- Validate before commit -- npm run validate (frontend) / pytest (backend)\n- scaffolding:tech-writer owns docs -- only tech-writer modifies README/CHANGELOG\n- scaffolding:developer owns code -- only developer modifies source files"
  }
}
EOF
exit 0
